use std::io::stdin;

fn read_n() -> (u64, u64) {
    let mut buffer = String::new();
    stdin().read_line(&mut buffer).unwrap();
    let snums: Vec<&str> = buffer.trim().split(" ").collect();
    (snums[0].parse::<u64>().unwrap(), snums[1].parse::<u64>().unwrap())
}

fn div2(x: u64) -> u64{
    if x % 2 == 0 {
        return x / 2;
    } else {
        return x / 2 + 1;
    }
}

fn get_n(n: u64, k: u64) -> u64 {
    if k == n && n % 2 == 0 {
        return n;
    }
    if k <= div2(n) {
        return k * 2 - 1;
    } else {
        return k % div2(n) * 2;
    }
}

fn testme() {
    for x in 1..11 {
        print!("{} ", get_n(10, x));
    }
    println!("Test#1 has been done");

    for x in 1..12 {
        print!("{} ", get_n(11, x));
    }
    println!("Test#2 has been done");
}

fn main() {
    let (n, k) = read_n();
    println!("{}", get_n(n, k));
